// Bootstrap/Features/WorkflowsExtensions.cs
using Nxgn.Actions.Api.Features.Admin.Workflows.Shared.Commands;
using Nxgn.Actions.Api.Features.Admin.Workflows.Shared.Mappers;
using Nxgn.Actions.Api.Features.Admin.Workflows.Shared.Queries;

namespace Nxgn.Actions.Api.Bootstrap.Features;

public static class WorkflowsExtensions
{
    public static IServiceCollection AddWorkflowsServices(this IServiceCollection services)
    {
        // Commands
        services.AddScoped<SaveWorkflowCommand>();
        services.AddScoped<DeleteWorkflowCommand>();

        // Queries
        services.AddScoped<GetWorkflowQuery>();
        services.AddScoped<GetWorkflowsQuery>();
        services.AddScoped<GetWorkflowsCountQuery>();

        // Mappers
        services.AddScoped<WorkflowEntityMapper>();
        services.AddScoped<WorkflowDTOMapper>();

        return services;
    }
}

// Bootstrap/Features/ActionsExtensions.cs
public static IServiceCollection AddActionsServices(this IServiceCollection services)
{
    // Commands
    services.AddScoped<SaveActionCommand>();
    services.AddScoped<DeleteActionCommand>();

    // Queries
    services.AddScoped<GetActionQuery>();
    services.AddScoped<GetActionsQuery>();
    services.AddScoped<GetActionsCountQuery>();

    // Mappers
    services.AddScoped<ActionEntityMapper>();
    services.AddScoped<ActionDTOMapper>();
    services.AddScoped<ActionDTOMapperDataContextService>();

    return services;
}

// Bootstrap/Features/ActionsExtensions.cs
public static IServiceCollection AddActionsServices(this IServiceCollection services)
{
    // Commands
    services.AddScoped<SaveActionCommand>();
    services.AddScoped<DeleteActionCommand>();
    services.AddScoped<UploadEvidenceCommand>();        // Sub-feature command
    services.AddScoped<SaveConsultationCommand>();       // Sub-feature command

    // Queries
    services.AddScoped<GetActionQuery>();
    services.AddScoped<GetActionsQuery>();
    services.AddScoped<GetActionsCountQuery>();
    services.AddScoped<GetActionEvidenceQuery>();        // Sub-feature query

    // Mappers
    services.AddScoped<ActionEntityMapper>();
    services.AddScoped<ActionDTOMapper>();
    services.AddScoped<ActionDTOMapperDataContextService>();

    return services;
}

// Bootstrap/Services.cs
namespace Nxgn.Actions.Api.Bootstrap;

public static class Services
{
    public static IServiceCollection AddServices(this IServiceCollection services)
    {
        return services
            // Actions
            .AddActionsServices()

            // Administration
            .AddWorkflowsServices()
            .AddComplianceProfilesServices()
            .AddEscalationRulesServices()

            // System
            .AddLanguagesServices();
    }
}
